#![cfg(feature = "hashes")]

use rscrypto::{Blake2b512, Blake2s256, Digest};

#[derive(Clone, Copy)]
struct OfficialCase {
  family: &'static str,
  input_hex: &'static str,
  key_hex: &'static str,
  output_hex: &'static str,
}

const fn case(
  family: &'static str,
  input_hex: &'static str,
  key_hex: &'static str,
  output_hex: &'static str,
) -> OfficialCase {
  OfficialCase {
    family,
    input_hex,
    key_hex,
    output_hex,
  }
}

