fn decode_hex(hex: &str) -> Vec<u8> {
  assert_eq!(hex.len() % 2, 0, "hex input length must be even");
  hex
    .as_bytes()
    .chunks_exact(2)
    .map(|pair| {
      let hi = (pair[0] as char).to_digit(16).expect("valid hex") as u8;
      let lo = (pair[1] as char).to_digit(16).expect("valid hex") as u8;
      (hi << 4) | lo
    })
    .collect()
}

fn assert_blake2b_case(case: OfficialCase) {
  let input = decode_hex(case.input_hex);
  let key = decode_hex(case.key_hex);
  let expected = decode_hex(case.output_hex);

  let actual = if key.is_empty() {
    Blake2b512::digest(&input).to_vec()
  } else {
    Blake2b512::keyed_digest(&key, &input).to_vec()
  };
  assert_eq!(
    actual,
    expected,
    "blake2b oneshot mismatch input_len={} key_len={}",
    input.len(),
    key.len()
  );

  let mut hasher = if key.is_empty() {
    Blake2b512::new()
  } else {
    Blake2b512::new_keyed(&key)
  };
  for chunk in input.chunks(17) {
    hasher.update(chunk);
  }
  assert_eq!(
    hasher.finalize().to_vec(),
    expected,
    "blake2b streaming mismatch input_len={} key_len={}",
    input.len(),
    key.len()
  );
}

fn assert_blake2s_case(case: OfficialCase) {
  let input = decode_hex(case.input_hex);
  let key = decode_hex(case.key_hex);
  let expected = decode_hex(case.output_hex);

  let actual = if key.is_empty() {
    Blake2s256::digest(&input).to_vec()
  } else {
    Blake2s256::keyed_digest(&key, &input).to_vec()
  };
  assert_eq!(
    actual,
    expected,
    "blake2s oneshot mismatch input_len={} key_len={}",
    input.len(),
    key.len()
  );

  let mut hasher = if key.is_empty() {
    Blake2s256::new()
  } else {
    Blake2s256::new_keyed(&key)
  };
  for chunk in input.chunks(11) {
    hasher.update(chunk);
  }
  assert_eq!(
    hasher.finalize().to_vec(),
    expected,
    "blake2s streaming mismatch input_len={} key_len={}",
    input.len(),
    key.len()
  );
}

#[test]
fn blake2_official_boundary_vectors() {
  for case in OFFICIAL_CASES {
    match case.family {
      "blake2b" => assert_blake2b_case(*case),
      "blake2s" => assert_blake2s_case(*case),
      other => panic!("unsupported official case family: {other}"),
    }
  }
}
